const body = $input.first().json.body || $input.first().json;

// Campos obligatorios
const required = ['client_name', 'project_name', 'project_type'];
const missing = required.filter(f => !body[f] || body[f].toString().trim() === '');

if (missing.length > 0) {
  return [{
    json: {
      valid: false,
      error: `Campos obligatorios faltantes: ${missing.join(', ')}`,
      missing_fields: missing
    }
  }];
}

// Validar project_type
const validTypes = ['reforma_integral', 'redistribucion', 'cambio_uso', 'adecuacion', 'apoyo_tecnico', 'otro'];
if (!validTypes.includes(body.project_type)) {
  return [{
    json: {
      valid: false,
      error: `project_type inválido. Valores permitidos: ${validTypes.join(', ')}`,
      received: body.project_type
    }
  }];
}

// Validar urgency si viene
const validUrgency = ['normal', 'alta', 'urgente'];
const urgency = body.urgency && validUrgency.includes(body.urgency) ? body.urgency : 'normal';

// Validar property_type si viene
const validPropertyTypes = ['piso', 'casa', 'local', 'atico', 'bajo', 'duplex', 'otro'];
const propertyType = body.property_type && validPropertyTypes.includes(body.property_type) ? body.property_type : null;

return [{
  json: {
    valid: true,
    client_name:        body.client_name.trim(),
    client_email:       body.client_email       || null,
    client_phone:       body.client_phone       || null,
    project_name:       body.project_name.trim(),
    project_type:       body.project_type,
    location_address:   body.location_address   || null,
    location_city:      body.location_city      || null,
    location_province:  body.location_province  || null,
    property_type:      propertyType,
    property_area_m2:   body.property_area_m2   ? parseFloat(body.property_area_m2) : null,
    budget_target:      body.budget_target      ? parseFloat(body.budget_target) : null,
    budget_flexible:    body.budget_flexible    === true || body.budget_flexible === 'true',
    urgency:            urgency,
    notes:              body.notes              || null
  }
}];

const input = $('Validate Input').first().json;
const existing = $input.first().json;

// Si el cliente ya existe, devolvemos su ID
if (existing.id) {
  return [{
    json: {
      client_id: existing.id,
      client_exists: true,
      ...input
    }
  }];
}

// Si no existe, marcamos para crear
return [{
  json: {
    client_id: null,
    client_exists: false,
    ...input
  }
}];

const merged = $input.first().json;
const validated = $('Check Client Exists').first().json;

// Determinar client_id: del merge (nuevo creado) o del existente
const clientId = merged.id || validated.client_id;

return [{
  json: {
    client_id:         clientId,
    project_name:      validated.project_name,
    project_type:      validated.project_type,
    budget_target:     validated.budget_target,
    budget_flexible:   validated.budget_flexible,
    location_address:  validated.location_address,
    location_city:     validated.location_city,
    location_province: validated.location_province,
    property_type:     validated.property_type,
    property_area_m2:  validated.property_area_m2,
    urgency:           validated.urgency,
    notes:             validated.notes
  }
}];

